import java.io.File;
import java.util.Scanner;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter file name:");
        String fileName = scanner.nextLine();

        if (isValidFileName(fileName)) {
            File directory = new File("/path/to/directory");
            File file = new File(directory, fileName);

            if (file.exists() && file.getAbsolutePath().startsWith(directory.getAbsolutePath())) {
                System.out.println("File exists!");
            } else {
                System.out.println("File does not exist.");
            }
        } else {
            System.out.println("Invalid file name!");
        }
    }

    private static boolean isValidFileName(String fileName) {
        // Implement your validation logic here
        // For example, restrict certain characters or patterns
        return !fileName.contains(".."); // Simple example to disallow parent directory traversal
    }
}

